/**
 * Notification model and related types.
 *
 * Defines the core notification data structures used throughout the system.
 * All notification delivery channels (email, webhook, SMS, etc.) work with
 * these types.
 */

/**
 * Supported notification channel types.
 * New channels are added here and implemented via NotificationAdapter.
 */
export type NotificationChannel = 'email' | 'webhook' | 'sms' | 'in-app';

/**
 * Semantic notification types describing why a notification is sent.
 */
export type NotificationType =
  | 'order:confirmation'
  | 'order:status-update'
  | 'user:welcome'
  | 'user:profile-updated';

/**
 * Priority levels for notification delivery.
 */
export type NotificationPriority = 'low' | 'normal' | 'high' | 'urgent';

/**
 * Payload for creating a notification. Services produce these;
 * the NotificationService dispatches them to adapters.
 */
export interface NotificationPayload {
  type: NotificationType;
  recipient: string;
  subject: string;
  body: string;
  channel: NotificationChannel;
  priority: NotificationPriority;
  metadata?: Record<string, string>;
}

/**
 * A notification record after it has been processed by the system.
 */
export interface Notification {
  id: string;
  type: NotificationType;
  recipient: string;
  subject: string;
  body: string;
  channel: NotificationChannel;
  priority: NotificationPriority;
  status: 'pending' | 'sent' | 'failed';
  metadata?: Record<string, string>;
  createdAt: Date;
  sentAt?: Date;
}

/**
 * Result returned by a NotificationAdapter after attempting delivery.
 */
export interface NotificationResult {
  success: boolean;
  notificationId: string;
  channel: NotificationChannel;
  error?: string;
}

/**
 * NotificationAdapter interface — the contract all delivery channels must implement.
 *
 * Architecture constraint: Every notification channel (email, webhook, SMS, etc.)
 * MUST implement this interface and be registered with the NotificationService.
 * The NotificationService dispatches to adapters based on the payload's `channel` field.
 *
 * To add a new notification channel:
 * 1. Add the channel name to NotificationChannel type in src/models/notification.ts
 * 2. Create a new adapter class implementing this interface in src/adapters/
 * 3. Register the adapter with NotificationService via registerAdapter()
 */

import type { NotificationPayload, NotificationResult } from '../models/notification.js';

export interface NotificationAdapter {
  /** The channel this adapter handles (must match a NotificationChannel value). */
  readonly channel: string;

  /**
   * Send a notification through this channel.
   * @param payload - The notification to deliver.
   * @returns Result indicating success or failure.
   */
  send(payload: NotificationPayload): Promise<NotificationResult>;
}

/**
 * Email notification adapter — delivers notifications via email.
 *
 * This is a stub implementation that logs email sends in-memory.
 * Replace the send() internals with a real email provider (SES, SendGrid, etc.)
 * while keeping the NotificationAdapter interface contract.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationPayload, NotificationResult } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/**
 * Configuration for the email adapter.
 */
export interface EmailAdapterConfig {
  fromAddress: string;
  replyToAddress?: string;
}

export class EmailAdapter implements NotificationAdapter {
  readonly channel = 'email' as const;
  private logger = new Logger('EmailAdapter');
  private sentEmails: Array<{ payload: NotificationPayload; sentAt: Date }> = [];

  constructor(private config: EmailAdapterConfig) {}

  /**
   * Send an email notification.
   *
   * Stub implementation: records the email in-memory and returns success.
   * In production, this would call an email provider API.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    this.logger.info(
      `Sending email from ${this.config.fromAddress} to ${payload.recipient}: ${payload.subject}`,
    );

    this.sentEmails.push({ payload, sentAt: new Date() });

    return {
      success: true,
      notificationId: payload.metadata?.notificationId ?? 'unknown',
      channel: 'email',
    };
  }

  /**
   * Get all emails sent through this adapter. Useful for testing.
   */
  getSentEmails(): Array<{ payload: NotificationPayload; sentAt: Date }> {
    return [...this.sentEmails];
  }

  /**
   * Clear sent emails log. Useful for testing.
   */
  clearSentEmails(): void {
    this.sentEmails = [];
  }
}

